// Event.js

import React, { useState, useEffect } from 'react';

const Event = () => {
  const [events, setEvents] = useState([]);
  const [newEvent, setNewEvent] = useState({ event_name: '', event_state: '' });

  // イベントリストを取得する
  const fetchEvents = async () => {
    const response = await fetch('http://localhost:8000/event/get');
    const data = await response.json();
    setEvents(data);
  };

  // コンポーネントのマウント時にイベントリストを取得
  useEffect(() => {
    fetchEvents();
  }, []);

  // 新しいイベントを登録する
  const registerEvent = async (e) => {
    e.preventDefault();
    await fetch('http://localhost:8000/event/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newEvent)
    });
    setNewEvent({ event_name: '', event_state: '' });
    fetchEvents(); // リストを更新
  };

  // イベントを更新する
  const updateEvent = async (id, name, state) => {
    await fetch(`http://localhost:8000/event/edit/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ event_id: id, event_name: name, event_state: state })
    });
    fetchEvents(); // リストを更新
  };

  // イベントを削除する
  const deleteEvent = async (eventId) => {
    await fetch(`http://localhost:8000/event/delete/${eventId}`, { method: 'DELETE' });
    fetchEvents(); // リストを更新
  };

  return (
    <div>
      <h2>イベント管理</h2>
      {/* イベント登録フォーム */}
      <form onSubmit={registerEvent}>
        {/* ... */}
      </form>
      {/* イベントリスト */}
      {events.map((event) => (
        <form
          key={event.event_id}
          onSubmit={(e) => {
            e.preventDefault();
            updateEvent(event.event_id, event.event_name, event.event_state);
          }}
        >
          <input
            type="text"
            value={event.event_name}
            onChange={(e) => setEvents(events.map(ev => ev.event_id === event.event_id ? { ...ev, event_name: e.target.value } : ev))}
          />
          <select
            value={event.event_state}
            onChange={(e) => setEvents(events.map(ev => ev.event_id === event.event_id ? { ...ev, event_state: e.target.value } : ev))}
          >
            {/* ... */}
          </select>
          <button type="submit">更新</button>
          <button type="button" onClick={() => deleteEvent(event.event_id)}>削除</button>
        </form>
      ))}
    </div>
  );
};

export default Event;
